    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "market_id": 0,
        //         "symbol": "ETH",
        //         "initial_margin_fraction": "5.00",
        //         "open_order_count": 0,
        //         "pending_order_count": 0,
        //         "position_tied_order_count": 0,
        //         "sign": 1,
        //         "position": "18.0193",
        //         "avg_entry_price": "2669.84",
        //         "position_value": "54306.566340",
        //         "unrealized_pnl": "6197.829558",
        //         "realized_pnl": "0.000000",
        //         "liquidation_price": "2191.1107231380406",
        //         "margin_mode": 0,
        //         "allocated_margin": "0.000000"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "market_id");
        market = this.safeMarket(marketId, market);
        Object sign = this.safeInteger(position, "sign");
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(sign, null)))
        {
            side = ((Helpers.isTrue((Helpers.isEqual(sign, 1))))) ? "long" : "short";
        }
        Object marginModeId = this.safeInteger(position, "margin_mode");
        Object marginMode = null;
        if (Helpers.isTrue(!Helpers.isEqual(marginModeId, null)))
        {
            marginMode = ((Helpers.isTrue((Helpers.isEqual(marginModeId, 0))))) ? "cross" : "isolated";
        }
        Object imfStr = this.safeString(position, "initial_margin_fraction");
        Object leverage = null;
        if (Helpers.isTrue(!Helpers.isEqual(imfStr, null)))
        {
            Object imf = this.parseToInt(imfStr);
            if (Helpers.isTrue(Helpers.isGreaterThan(imf, 0)))
            {
                leverage = Helpers.divide(100, imf);
            }
        }
        final Object finalMarket = market;
        final Object finalMarginMode = marginMode;
        final Object finalSide = side;
        final Object finalLeverage = leverage;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", null );
            put( "datetime", null );
            put( "isolated", (Helpers.isEqual(finalMarginMode, "isolated")) );
            put( "hedged", null );
            put( "side", finalSide );
            put( "contracts", LighterCore.this.safeNumber(position, "position") );
            put( "contractSize", null );
            put( "entryPrice", LighterCore.this.safeNumber(position, "avg_entry_price") );
            put( "markPrice", null );
            put( "notional", LighterCore.this.safeNumber(position, "position_value") );
            put( "leverage", finalLeverage );
            put( "collateral", LighterCore.this.safeNumber(position, "allocated_margin") );
            put( "initialMargin", null );
            put( "maintenanceMargin", null );
            put( "initialMarginPercentage", null );
            put( "maintenanceMarginPercentage", null );
            put( "unrealizedPnl", LighterCore.this.safeNumber(position, "unrealized_pnl") );
            put( "liquidationPrice", LighterCore.this.safeNumber(position, "liquidation_price") );
            put( "marginMode", finalMarginMode );
            put( "percentage", null );
        }});
    }

