    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        //     {
        //         "trade_id": 17609,
        //         "tx_hash": "99ffeaa3899fbaa51043840ddf762fd18c182a33b5125092105bee57af11fab04edf5fd90e969abd",
        //         "type": "trade",
        //         "market_id": 0,
        //         "size": "10.2304",
        //         "price": "2958.75",
        //         "usd_amount": "30269.196000",
        //         "ask_id": 281474977339869,
        //         "bid_id": 562949952870533,
        //         "ask_client_id": 0,
        //         "bid_client_id": 0,
        //         "ask_account_id": 20,
        //         "bid_account_id": 1077,
        //         "is_maker_ask": true,
        //         "block_height": 102070,
        //         "timestamp": 1766386112741,
        //         "taker_position_size_before": "0.0000",
        //         "taker_entry_quote_before": "0.000000",
        //         "taker_position_sign_changed": true,
        //         "maker_position_size_before": "-1856.8547",
        //         "maker_entry_quote_before": "5491685.069325",
        //         "maker_initial_margin_fraction_before": 500
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "market_id");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object accountIndex = this.safeString(trade, "account_index");
        Object askAccountId = this.safeString(trade, "ask_account_id");
        Object bidAccountId = this.safeString(trade, "bid_account_id");
        Object isMakerAsk = this.safeBool(trade, "is_maker_ask");
        Object side = null;
        Object orderId = null;
        if (Helpers.isTrue(!Helpers.isEqual(accountIndex, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(accountIndex, askAccountId)))
            {
                side = "sell";
                orderId = this.safeString(trade, "ask_id");
            } else if (Helpers.isTrue(Helpers.isEqual(accountIndex, bidAccountId)))
            {
                side = "buy";
                orderId = this.safeString(trade, "bid_id");
            }
        }
        Object takerOrMaker = null;
        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(side, null)) && Helpers.isTrue(!Helpers.isEqual(isMakerAsk, null))))
        {
            Object isMaker = ((Helpers.isTrue((Helpers.isEqual(side, "sell"))))) ? isMakerAsk : !Helpers.isTrue(isMakerAsk);
            takerOrMaker = ((Helpers.isTrue(isMaker))) ? "maker" : "taker";
        }
        final Object finalMarket = market;
        final Object finalOrderId = orderId;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", LighterCore.this.safeString(trade, "trade_id") );
            put( "timestamp", timestamp );
            put( "datetime", LighterCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", finalOrderId );
            put( "type", LighterCore.this.safeString(trade, "type") );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", LighterCore.this.safeString(trade, "price") );
            put( "amount", LighterCore.this.safeString(trade, "size") );
            put( "cost", LighterCore.this.safeString(trade, "usd_amount") );
            put( "fee", null );
        }}, market);
    }

